def test_create_training_course_missing_mandatory_title_returns_400(admin_auth_token, api_client):
    payload = {
        "description": "NEG test - title omitted",
        "duration_hours": 4,
        "is_mandatory": False
    }
    resp = api_client.post(
        "/api/training-courses",
        json=payload,
        headers={"Authorization": f"Bearer {admin_auth_token}"}
    )
    assert resp.status_code == 400, f"Expected 400, got {resp.status_code}"
    error_body = resp.json()
    error_text = str(error_body).lower()
    assert "title" in error_text, "Error body must reference the missing 'title' field"

