def test_create_training_course_module_disabled_returns_error(admin_auth_token, api_client, unique_title, disable_training_module):
    with disable_training_module():
        payload = {
            "title": unique_title("STC-Disabled"),
            "description": "STC module-disabled boundary test",
            "duration_hours": 2,
            "is_mandatory": False
        }
        resp = api_client.post(
            "/api/training-courses",
            json=payload,
            headers={"Authorization": f"Bearer {admin_auth_token}"}
        )
        assert resp.status_code in (400, 403, 503), (
            f"Expected 400/403/503 when module is disabled, got {resp.status_code}"
        )
        body = resp.json()
        assert not body.get("id"), "No entity id should be returned when module is disabled"
